-- ============================================================
--  VELOX COURIER — Datos iniciales
--  Ejecutar en SSMS con la BD velox_courier seleccionada
--  ORDEN: 1.Zonas→2.Origenes→3.Distritos→4.Tiendas→5.Motorizados→6.Ordenes
-- ============================================================

USE velox_courier;
GO

-- ══════════════════════════════════════════════════════════
-- PASO 1: Limpiar tablas (por si se ejecuta más de una vez)
-- ══════════════════════════════════════════════════════════
DELETE FROM ordenes;
DELETE FROM caja_pagos_tiendas;
DELETE FROM caja_pagos_motorizados;
DELETE FROM distritos;
DELETE FROM motorizados;
DELETE FROM tiendas;
DELETE FROM origenes;
DELETE FROM zonas;
-- Resetear identidades
DBCC CHECKIDENT ('zonas',           RESEED, 0);
DBCC CHECKIDENT ('origenes',        RESEED, 0);
DBCC CHECKIDENT ('distritos',       RESEED, 0);
DBCC CHECKIDENT ('tiendas',         RESEED, 0);
DBCC CHECKIDENT ('motorizados',     RESEED, 0);
DBCC CHECKIDENT ('ordenes',         RESEED, 1000);
GO

